import { IMessageComposer } from '@nitrots/nitro-renderer';

export class ATMDepositComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(amount: number) {
        // Sanitize / clamp
        const amt = Math.max(0, Math.floor(amount || 0));

        this._data = [amt];
        console.log('[📤] ATMDepositComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
